const TIME_ZONE = "America/New_York";
const input = $input.first()?.json || {};
const overrideTodayIso = input.override_today_iso || "";
const now = new Date();

function isoDateInTimezone(date, timeZone) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(date);

  const byType = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${byType.year}-${byType.month}-${byType.day}`;
}

const todayIso = overrideTodayIso || isoDateInTimezone(now, TIME_ZONE);

return [
  {
    json: {
      today_iso: todayIso,
      run_id: `blog-${todayIso}-${now.getTime()}`,
      timezone: TIME_ZONE,
    },
  },
];

const context = $("Set Today").first().json;
const targetIso = context.today_iso;

function clean(value) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim();
}

function getField(row, fieldName) {
  if (row[fieldName] !== undefined) return row[fieldName];

  const normalizedFieldName = clean(fieldName).toLowerCase();
  const match = Object.entries(row).find(([key]) => clean(key).toLowerCase() === normalizedFieldName);
  if (match) return match[1];

  const fallbackColumns = {
    "Publish Date": "col_2",
    "Day": "col_3",
    "Wk": "col_4",
    "Industry": "col_5",
    "Funnel Stage": "col_6",
    "Post Title": "col_7",
    "Content Type": "col_8",
    "Target Word Count": "col_9",
    "Primary Keyword": "col_10",
    "Secondary Keywords (2-3)": "col_11",
    "LSI Keywords (4-6)": "col_12",
    "Search Intent": "col_13",
    "Pain Point": "col_14",
    "How AI Fixes It": "col_15",
    "Content Brief Outline (H2 Structure)": "col_16",
    "Recommended CTA": "col_17",
    "Meta Title (<60 chars)": "col_18",
    "Meta Description (<160 chars)": "col_19",
    "Research / Source URL": "col_20",
  };

  if (fieldName === "#") {
    const firstDataKey = Object.keys(row).find((key) => key !== "row_number" && !/^col_\d+$/i.test(key));
    return firstDataKey ? row[firstDataKey] : "";
  }

  const fallbackKey = fallbackColumns[fieldName];
  return fallbackKey && row[fallbackKey] !== undefined ? row[fallbackKey] : "";
}

function parseSheetDate(value) {
  if (value === null || value === undefined || value === "") return "";

  if (typeof value === "number") {
    const excelEpoch = Date.UTC(1899, 11, 30);
    return new Date(excelEpoch + value * 86400000).toISOString().slice(0, 10);
  }

  const text = String(value).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(text)) return text;

  const parsed = new Date(text);
  if (Number.isNaN(parsed.getTime())) return "";

  return parsed.toISOString().slice(0, 10);
}

const rows = $input.all().filter((item) => {
  const publishDate = getField(item.json, "Publish Date");
  return publishDate && clean(publishDate).toLowerCase() !== "publish date";
});

const match = rows.find((item) => {
  const publishDate = getField(item.json, "Publish Date");
  return parseSheetDate(publishDate) === targetIso;
});

if (!match) {
  return [];
}

const row = match.json;

return [
  {
    json: {
      ...context,
      blog_number: getField(row, "#"),
      publish_date: getField(row, "Publish Date"),
      industry: getField(row, "Industry"),
      funnel_stage: getField(row, "Funnel Stage"),
      post_title: getField(row, "Post Title"),
      content_type: getField(row, "Content Type"),
      target_word_count: getField(row, "Target Word Count"),
      primary_keyword: getField(row, "Primary Keyword"),
      secondary_keywords: getField(row, "Secondary Keywords (2-3)"),
      lsi_keywords: getField(row, "LSI Keywords (4-6)"),
      search_intent: getField(row, "Search Intent"),
      pain_point: getField(row, "Pain Point"),
      how_ai_fixes_it: getField(row, "How AI Fixes It"),
      outline: getField(row, "Content Brief Outline (H2 Structure)"),
      cta: getField(row, "Recommended CTA"),
      meta_title: getField(row, "Meta Title (<60 chars)"),
      meta_description: getField(row, "Meta Description (<160 chars)"),
      source_url: getField(row, "Research / Source URL"),
    },
  },
];

const source = $("Pick Today's Row").first().json;
const response = $input.first()?.json || {};

const PLANNING_SECTION_TITLES = [
  "Entity Signals",
  "Suggested Internal Links",
  "Internal Link Suggestions",
  "SEO Notes",
  "Editorial Notes",
  "Implementation Notes",
  "External Source Note",
  "FAQ Schema",
  "Schema Markup",
];

function stripFence(value) {
  return String(value || "")
    .trim()
    .replace(/^```(?:json|html|markdown)?/i, "")
    .replace(/```$/i, "")
    .trim();
}

function slugify(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function escapeAttribute(value) {
  return escapeHtml(value).replace(/`/g, "&#96;");
}

function planningTitlePattern() {
  return PLANNING_SECTION_TITLES.map((title) => title.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|");
}

function stripPlanningSections(value) {
  let text = String(value || "").trim();
  if (!text) return "";

  const titles = planningTitlePattern();
  const htmlHeading = new RegExp(`\\s*<h[1-6][^>]*>\\s*(?:${titles})\\s*<\\/h[1-6]>[\\s\\S]*$`, "i");
  const plainHeading = new RegExp(`(?:^|\\n)\\s*(?:#{1,6}\\s*)?(?:${titles})\\s*:?[\\s\\S]*$`, "i");

  text = text.replace(htmlHeading, "").replace(plainHeading, "");
  return text.replace(/<hr\s*\/?>\s*$/i, "").trim();
}

function inlineMarkdownToHtml(value) {
  return escapeHtml(value)
    .replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>")
    .replace(/\[([^\]]+)\]\((https?:\/\/[^)\s]+|\/[^)\s]+|#[^)\s]+)\)/g, (_match, label, href) => {
      return `<a href="${escapeAttribute(href)}">${label}</a>`;
    });
}

function cleanHtmlMarkdownArtifacts(value) {
  return stripPlanningSections(value)
    .replace(/\*\*([^*<>]+)\*\*/g, "<strong>$1</strong>")
    .replace(/\[([^\]<]+)\]\((https?:\/\/[^)\s]+|\/[^)\s]+|#[^)\s]+)\)/g, (_match, label, href) => {
      return `<a href="${escapeAttribute(href)}">${label}</a>`;
    })
    .trim();
}

function markdownToHtml(markdown) {
  const lines = stripPlanningSections(markdown).split(/\r?\n/);
  const html = [];
  let inList = false;
  let listTag = "ul";

  function closeList() {
    if (inList) {
      html.push(`</${listTag}>`);
      inList = false;
    }
  }

  for (const rawLine of lines) {
    const line = rawLine.trim();

    if (!line) {
      closeList();
      continue;
    }

    if (line.startsWith("### ")) {
      closeList();
      html.push(`<h3>${inlineMarkdownToHtml(line.slice(4))}</h3>`);
    } else if (line.startsWith("## ")) {
      closeList();
      html.push(`<h2>${inlineMarkdownToHtml(line.slice(3))}</h2>`);
    } else if (line.startsWith("# ")) {
      closeList();
      html.push(`<h1>${inlineMarkdownToHtml(line.slice(2))}</h1>`);
    } else if (/^[-*]\s+/.test(line)) {
      if (!inList || listTag !== "ul") {
        closeList();
        listTag = "ul";
        html.push("<ul>");
        inList = true;
      }
      html.push(`<li>${inlineMarkdownToHtml(line.replace(/^[-*]\s+/, ""))}</li>`);
    } else if (/^\d+\.\s+/.test(line)) {
      if (!inList || listTag !== "ol") {
        closeList();
        listTag = "ol";
        html.push("<ol>");
        inList = true;
      }
      html.push(`<li>${inlineMarkdownToHtml(line.replace(/^\d+\.\s+/, ""))}</li>`);
    } else {
      closeList();
      html.push(`<p>${inlineMarkdownToHtml(line)}</p>`);
    }
  }

  closeList();
  return html.join("\n");
}

function normalizeJsonLd(value) {
  if (!value) return "";

  if (typeof value === "object") {
    return JSON.stringify(value);
  }

  const text = stripFence(value);
  if (!text) return "";

  try {
    return JSON.stringify(JSON.parse(text));
  } catch (error) {
    return "";
  }
}

const content =
  response.choices?.[0]?.message?.content ||
  response.message?.content ||
  response.content ||
  response.text ||
  "";

function parseTaggedOutput(value) {
  const text = String(value || "");
  const fields = [
    "generated_title",
    "slug",
    "meta_title",
    "meta_description",
    "excerpt",
    "image_prompt",
    "image_alt",
    "alt_text",
    "caption",
    "faq_schema_json",
    "blog_markdown",
    "blog_html",
  ];

  const output = {};

  for (const field of fields) {
    const pattern = new RegExp(`<${field}>\\s*([\\s\\S]*?)\\s*<\\/${field}>`, "i");
    const match = text.match(pattern);
    output[field] = match ? match[1].trim() : "";
  }

  if (!output.generated_title && !output.blog_markdown && !output.blog_html) {
    throw new Error("Could not parse Blog Creation output as structured fields, JSON, or tagged text.");
  }

  return output;
}

let blog;

if (response.generated_title || response.blog_markdown || response.blog_html) {
  blog = response;
} else if (typeof content === "object" && content !== null) {
  blog = content;
} else {
  const cleaned = stripFence(content);
  try {
    blog = JSON.parse(cleaned);
  } catch (error) {
    blog = parseTaggedOutput(cleaned);
  }
}

const title = blog.generated_title || blog.title || source.post_title;
const slug = slugify(blog.slug || title);
const blogMarkdown = stripPlanningSections(blog.blog_markdown || blog.markdown || "");
const rawBlogHtml = blog.blog_html || blog.html || "";
const blogHtml = cleanHtmlMarkdownArtifacts(rawBlogHtml || markdownToHtml(blogMarkdown));
const imageAlt = blog.image_alt || blog.alt_text || blog.image_alt_text || "";

if (!String(blogMarkdown || "").trim() && !String(blogHtml || "").trim()) {
  throw new Error("Blog Creation produced title/meta data but no blog_markdown or blog_html body.");
}

return [
  {
    json: {
      ...source,
      generated_title: title,
      slug,
      meta_title: blog.meta_title || source.meta_title,
      meta_description: blog.meta_description || source.meta_description,
      excerpt: blog.excerpt || "",
      blog_markdown: blogMarkdown,
      blog_html: blogHtml,
      image_prompt: blog.image_prompt || "",
      image_alt: imageAlt,
